#include <stack>
#include <set>
using namespace std;

int main()
{
    int t;
    scanf("%d", &t);
    while(t--)
    {
        int n, x;
        scanf("%d%d", &n, &x);
        int a[n];
        for(int i=0; i<n; i++) scanf("%d", &a[i]);
        int maxn=0;
        for(int i=0; i<n; i++)
        {
            maxn=max(maxn, a[i]);
        }
        maxn+=x;
        printf("%d\n", maxn);
    }
    return 0;
}
